#include <bits/stdc++.h>
using namespace std;
long long a(long long n){
	long long ans=n,mgs=n;
	    while(mgs>=3){
	        ans+=mgs/3;
	        mgs=mgs/3+mgs%3;
	    }
	    return ans;
}
int main(){
    long long n;
    cin>>n;
    long long l=1,r=n,mid,z;
    while(l<=r){
		mid=(l+r)/2;
		long long c=a(mid);
		if(c>=n){
			z=mid;
			r=mid-1;
		}
		else{
			l=mid+1;
		}
	}
	cout<<z;
    return 0;
}
